function parseMaybeJson(value, fallback) {
  if (value === null || value === undefined) return fallback;
  if (typeof value === "object") return value;

  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch {
      return fallback;
    }
  }

  return fallback;
}

const input = $json;

const lead = parseMaybeJson(input.lead, {});
const state = parseMaybeJson(input.state, {});
const conversation = parseMaybeJson(input.conversation, {});
const metadata = parseMaybeJson(input.metadata, {});

if (!input.lead_id) {
  throw new Error("Missing lead_id");
}

if (!input.reason) {
  throw new Error("Missing handoff reason");
}

return [
  {
    ...input,
    lead,
    state,
    conversation,
    metadata,
    validated_at: new Date().toISOString()
  }
];

const lead = $json.lead || {};
const state = $json.state || {};

let assigned_to = "contacto@aahumada.com";
let assigned_team = "ventas";
let priority = "normal";

if (($json.reason || "").toLowerCase().includes("reclamo")) {
  assigned_team = "soporte";
  priority = "high";
}

if (state.stage === "closing" || state.stage === "quoted") {
  assigned_team = "ventas";
}

return [{
  ...$json,
  assigned_to,
  assigned_team,
  priority
}];

const lead = $json.lead || {};
const state = $json.state || {};
const conversation = $json.conversation || {};

const text = [
  `Nuevo handoff humano`,
  `Caso ID: ${$json.id || "sin_id"}`,
  `Lead ID: ${lead.id || $json.lead_id}`,
  `Nombre: ${lead.name || "Sin nombre"}`,
  `Teléfono: ${lead.phone || "Sin teléfono"}`,
  `Etapa: ${state.stage || "sin_stage"}`,
  `Razón: ${$json.reason || "sin razón"}`,
  `Resumen: ${$json.summary || "sin resumen"}`,
  `Último mensaje: ${conversation.latest_user_message || "sin mensaje"}`,
  `Servicio: ${state.service_interest || "N/D"}`,
  `Vehículo: ${state.vehicle_type || "N/D"}`,
  `Comuna: ${state.district || "N/D"}`,
  `Asignado a: ${$json.assigned_to || "N/D"}`
].join('\n');

return [{
  ...$json,
  notification_text: text
}];

const caseRow = (() => {
  try {
    return $("update_handoff_notification_status").first().json;
  } catch {
    try {
      return $("insert_handoff_case").first().json;
    } catch {
      return {};
    }
  }
})();

const owner = (() => {
  try {
    return $("assign_handoff_owner").first().json;
  } catch {
    return {};
  }
})();

const notificationSent =
  caseRow.notification_sent === true ||
  !!caseRow.notification_sent_at ||
  !!caseRow.notified_at;

return [
  {
    handoff: true,

    handoff_case_id: caseRow.id || null,
    lead_id: caseRow.lead_id || owner.lead_id || $json.lead_id || null,

    assigned_to: caseRow.assigned_to || owner.assigned_to || null,
    assigned_team: caseRow.assigned_team || owner.assigned_team || null,
    priority: caseRow.priority || owner.priority || "normal",

    notification_sent: notificationSent,
    notification_channel: caseRow.notification_channel || "email",
    notification_sent_at:
      caseRow.notification_sent_at ||
      caseRow.notified_at ||
      null,

    summary: caseRow.summary || owner.summary || null,
    reason: caseRow.reason || owner.reason || null,

    handoff_operational: {
      human_handoff: true,
      handoff_case_created: !!caseRow.id,
      assigned: !!(caseRow.assigned_to || owner.assigned_to),
      notification_sent: notificationSent
    }
  }
];

